from typing import List

class Solution:
    def earliestSecondToMarkIndices(self, nums: List[int], changeIndices: List[int]) -> int:
        n = len(nums)
        m = len(changeIndices)
        required = [0] * (n + 1)  # 1-based indexing
        for i in range(1, n + 1):
            required[i] = nums[i - 1]

        # Preprocess the last occurrence of each index in changeIndices
        last_occurrence = [0] * (n + 1)
        for t in range(m):
            idx = changeIndices[t]
            last_occurrence[idx] = t + 1  # 1-based time

        # Check if all indices are present in changeIndices
        for i in range(1, n + 1):
            if last_occurrence[i] == 0:
                return -1

        # Binary search on the answer
        low = 1
        high = m
        answer = -1

        while low <= high:
            mid = (low + high) // 2
            time_used = 0
            marked = [False] * (n + 1)
            required_copy = required.copy()

            for t in range(mid):
                idx = changeIndices[t]
                if required_copy[idx] == 0 and not marked[idx]:
                    marked[idx] = True
                    time_used += 1
                else:
                    time_used += 1
                    required_copy[idx] -= 1

            if all(marked) and time_used <= mid:
                answer = mid
                high = mid - 1
            else:
                low = mid + 1

        return answer
